INSERT INTO product_variants (id, product_id, sku, slug, variant_name, service_type_id, duration_display, duration_weeks_min, duration_weeks_max, delivery_complexity, implementation_model, badge, positioning, is_default_variant, status) VALUES (216, 3, 'SEC-BUN-216', 'governance-risk-compliance-high-impact-transformation-bundle-216', 'Transformation Bundle', 'bundle', '16-24 Weeks', 16, 24, 'high', 'TMaaS Managed Delivery', 'Bundle', 'From control design to continuous compliance: a GRC capability built, deployed, and operated under a single programme.', false, 'published');
