INSERT INTO product_variants (id, product_id, sku, slug, variant_name, service_type_id, duration_display, duration_weeks_min, duration_weeks_max, delivery_complexity, implementation_model, badge, positioning, is_default_variant, status) VALUES (219, 4, 'AI-BUN-219', 'enterprise-data-platform-high-impact-transformation-bundle-219', 'Transformation Bundle', 'bundle', '16-24 Weeks', 16, 24, 'high', 'TMaaS Managed Delivery', 'Bundle', 'A governed data platform designed for scale, deployed for quality, and managed so trust in data compounds over time.', false, 'published');
